		"stabilize the position": "\u7a33\u4f4f\u5c40\u9762",
		"simplify into a cleaner position": "\u7b80\u5316\u5230\u66f4\u6613\u63a7\u5236\u7684\u5c40\u9762",
		"improve piece placement": "\u6539\u5584\u5b50\u529b\u7ad9\u4f4d",
		"keep the initiative": "\u7ee7\u7eed\u638c\u63a7\u4e3b\u52a8\u6743",
		"bring the king out early": "\u8fc7\u65e9\u628a\u738b\u8d70\u51fa\u6765",
		"bring the queen out too soon": "\u8fc7\u65e9\u51fa\u540e",
		"spend a tempo on a flank pawn": "\u628a\u4e00\u6b65\u8282\u594f\u82b1\u5728\u8fb9\u5175\u4e0a",
		"Pawn structure": "兵形",
		"Squares": "格子",
		"Minor pieces": "轻子",
		"Endgame": "残局",
